import { Component, h, Element, Prop, State, Event, EventEmitter } from '@stencil/core';
import { LayoutCssClasses, LayoutType } from './mx-layout.model';
import { addGlobalStylesToShadowRoot, parseObjectSilent } from '@src/utils/mx-utils/utils';

@Component({
  tag: 'mx-layout',
  styleUrl: 'mx-layout.css',
  shadow: true
})
export class MxLayout {

  @Element() hostElement: HTMLMxLayoutElement;

  /** Sets the type of layout. */
  @Prop() readonly layoutType: LayoutType = LayoutType.FULL_PAGE;

  /** Adds custom css class for each block. */
  @Prop() readonly cssClasses: string = '';

  /** Determines if prominent header is collapsable or not. */
  @Prop() readonly prominentHeaderIsCollapsable: boolean = false;

  /** Determines if prominent header is expanded upon initial load. */
  @Prop() readonly prominentHeaderIsExpanded: boolean = false;

  /** Sets Prominent title text. */
  @Prop() readonly prominentTitleText: string = '';

  /** Determines if back button is shown in title area. */
  @Prop() readonly hasBackButton: boolean = false;

  /** This event is emitted when the user clicks the back button in title.*/
  @Event() backButtonClick: EventEmitter;

  @State() private prominentHeaderCollapsed = !this.prominentHeaderIsExpanded;

  private hasTitleSlot = false;
  private hasProminentHeaderSlot = false;
  private hasProminentHeaderIconSlot = false;
  private prominentHeaderRef: Element;

  componentWillLoad() {
    this.hasTitleSlot = this.hostElement.querySelector('[slot=\'title\']') != null;
    this.hasProminentHeaderSlot = this.hostElement.querySelector('[slot=\'prominent-header\']') != null;
    this.hasProminentHeaderIconSlot = this.hostElement.querySelector('[slot=\'prominent-icon\']') != null;
    this.hostElement.shadowRoot && addGlobalStylesToShadowRoot(this.hostElement.shadowRoot);
  }

  private getCssClass(block: string): string {
    const cssClassesObj: LayoutCssClasses = parseObjectSilent(this.cssClasses);
    return cssClassesObj.hasOwnProperty(block) ? cssClassesObj[block] : '';
  }

  private readonly toggleProminentSection = (event) => {
    // 3.25rem the height of the top area
    const targetHeight = 52;

    const y = event.clientY - this.prominentHeaderRef.getBoundingClientRect().top;

    if (y < targetHeight) {
      this.prominentHeaderCollapsed = !this.prominentHeaderCollapsed;
    }
  };

  render() {
    const contentSlots = [];
    switch (this.layoutType) {
      case LayoutType.LEFT_COLUMN:
        contentSlots.push([
          <div class={{
            'col-span-3 ': true,
            [this.getCssClass('leftColumn')]: true
          }}>
            <slot name='left-column' />
          </div>,
          <div class={{
            'col-span-9 ': true,
            [this.getCssClass('content')]: true
          }}>
            <slot />
          </div>
        ]);
        break;
      case LayoutType.THREE_COLUMNS:
        contentSlots.push([
          <div class={{
            'col-span-3 ': true,
            [this.getCssClass('leftColumn')]: true
          }}>
            <slot name='left-column' />
          </div>,
          <div class={{
            'col-span-6 ': true,
            [this.getCssClass('content')]: true
          }}>
            <slot />
          </div>,
          <div class={{
            'col-span-3 ': true,
            [this.getCssClass('rightColumn')]: true
          }}>
            <slot name='right-column' />
          </div>
        ]);
        break;
      case LayoutType.FULL_PAGE:
      default:
        contentSlots.push(
          <div class={{
            'col-span-full ': true,
            [this.getCssClass('content')]: true
          }}>
            <slot />
          </div>
        );
    }

    const titleCssClasses: string[] = [
      'mx-layout__title',
      'w-full',
      'overflow-hidden',
      'bg-default-50',
      'border-neutral-less-subtle',
      'flex',
      'flex-nowrap',
      'justify-start',
      'content-start'
    ];

    return (
      <div class={{
        'grid w-full': true,
        'grid-rows-mx-layout': !this.hasTitleSlot,
        'grid-rows-mx-layout_with-title': this.hasTitleSlot,
        'mx-layout bg-secondary': true
      }}>
        {this.hasTitleSlot && (
          <div class={{
            [titleCssClasses.join(' ')]: true,
            [this.getCssClass('title')]: true
          }}>
            {
              this.hasBackButton && <div class='flex'>
                <kds-link
                  class='pr-8 text-accent-more-prominent'
                  onClick={() => this.backButtonClick.emit()}
                  size='l'>&lt; Back</kds-link>
                <div class='back-button-divider rounded-extra-small mr-8'></div>
              </div>
            }
            <div class='mx-layout__title-text font-secondary font-bold heading-l'>
              <slot name='title' />
            </div>
            <div class='flex-grow'><slot name='title-right-content'/></div>
          </div>
        )}
        <div class={{
          'grid grid-cols-12 col-span-full gap-x-6 gap-y-4 mx-layout__content-container': true,
          [this.getCssClass('container')]: true
        }}>
          {(this.hasProminentHeaderSlot && !this.prominentHeaderIsCollapsable) && (
            <div class={{
              'mx-layout__prominent-header': true,
              'bg-accent-more-subtle px-16 py-16 border border-accent-most-prominent rounded-8 col-span-full': true,
              [this.getCssClass('prominent-header')]: true
            }}>
              <slot name='prominent-header' />
            </div>
          )}
          {(this.hasProminentHeaderSlot && this.prominentHeaderIsCollapsable) && (
            <div class={{
              'mx-layout__prominent-header is-collapsible': true,
              'mx-layout__prominent-header-collapsed': this.prominentHeaderCollapsed,
              'bg-accent-more-subtle px-16  border border-accent-most-prominent rounded-8 col-span-full': true,
              [this.getCssClass('prominent-header')]: true
            }}
            aria-expanded={!this.prominentHeaderCollapsed}
            onClick={this.toggleProminentSection}
            ref={(ref) => this.prominentHeaderRef = ref}
            >
              <div class={{
                'mx-layout__prominent-header-wrapper h-full': true
              }}>
                <div style={{ width: '100%', height: '20px' }}
                  class={{
                    'flex items-center justify-between mb-8': true
                  }}
                >
                  <div class='flex items-center min-w-0'
                  >
                    <kds-icon-chevron-down
                      size='s'
                      class={{
                        'mx-kds-icon': true,
                        'up-arrow': !this.prominentHeaderCollapsed
                      }}
                    />
                    <span class='body-m font-base prominent-title truncate pl-4' title={this.prominentTitleText}>
                      {this.prominentTitleText}
                    </span>

                    <span class='prominent-title-icon-slot-container'
                      style={{ display: this.hasProminentHeaderIconSlot ? 'inline-flex' : 'none' }}>
                      <slot name='prominent-icon' />
                    </span>
                  </div>
                </div>
                <div
                  class={{
                    'prominent-header-body h-full body-m': true,
                    hidden: this.prominentHeaderCollapsed
                  }}
                >
                  <slot name='prominent-header' />
                </div>
              </div>
            </div>
          )}

          {contentSlots.map((s) => s)}
        </div>
      </div>
    );
  }
}
